import{_ as o,o as a,c as d,a2 as l}from"./chunks/framework.VshInwhI.js";const p=JSON.parse('{"title":"持久化规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/backend/07-persistence.md","filePath":"mango-pmo/rules/backend/07-persistence.md"}'),c={name:"mango-pmo/rules/backend/07-persistence.md"};function i(t,e,n,r,s,u){return a(),d("div",null,[...e[0]||(e[0]=[l('<h1 id="持久化规范" tabindex="-1">持久化规范 <a class="header-anchor" href="#持久化规范" aria-label="Permalink to &quot;持久化规范&quot;">​</a></h1><h2 id="_0-mango-持久化基线" tabindex="-1">0. Mango 持久化基线 <a class="header-anchor" href="#_0-mango-持久化基线" aria-label="Permalink to &quot;0. Mango 持久化基线&quot;">​</a></h2><ul><li>Mango 关系型持久化统一通过 <code>mango-infra-persistence-starter</code> 接入。</li><li>当前 <code>mango-infra-persistence-starter</code> 的实现基于 MyBatis-Plus，但业务代码和业务模板必须优先使用 Mango 暴露的实体、CRUD Service 和 Controller 抽象。</li><li>Mango 开发者可以维护 MyBatis-Plus 适配、<code>MangoCrudService</code>、<code>MangoCrudServiceImpl</code>、<code>BaseCrudController</code>、审计、租户、Flyway 和 schema validation 等框架能力。</li><li>业务开发者不得在普通 CRUD 场景直接继承 MyBatis-Plus <code>ServiceImpl</code> 绕过 Mango CRUD 基线；复杂查询可以使用自定义 Mapper 和 XML，但必须保留租户、权限和事务边界。</li><li>业务代码禁止直接使用 JDBC，包括 <code>JdbcTemplate</code>、<code>java.sql.Connection</code>、<code>Statement</code>、<code>PreparedStatement</code>、<code>ResultSet</code>。</li><li>业务 Mapper 禁止使用注解 SQL，包括 <code>@Select</code>、<code>@Insert</code>、<code>@Update</code>、<code>@Delete</code>、<code>@*Provider</code>；自定义 SQL 必须写在 <code>mapper.xml</code>。</li><li>Mango CLI、starter 和业务模块模板必须生成真实数据库 CRUD 骨架，禁止生成内存 mock、固定返回值或未接数据库的接口壳。</li><li>具体接入方式、租户、数据权限、分页和联表查询示例见 Mango 文档站的 Persistence 持久化 README；能力总览见 Mango 能力地图。</li></ul><h2 id="_0-1-业务-crud-模板要求" tabindex="-1">0.1 业务 CRUD 模板要求 <a class="header-anchor" href="#_0-1-业务-crud-模板要求" aria-label="Permalink to &quot;0.1 业务 CRUD 模板要求&quot;">​</a></h2><p>业务 CRUD 模板至少必须生成以下闭环：</p><ul><li>migration SQL：创建真实业务表，包含 <code>id</code>、<code>tenant_id</code>、<code>created_by</code>、<code>created_at</code>、<code>updated_by</code>、<code>updated_at</code>。</li><li>Entity：继承 <code>TenantEntity</code>，表名和字段与 migration 一致。</li><li>Mapper：继承 <code>BaseMapper&lt;Entity&gt;</code>，只承担数据访问。</li><li>Service：继承 <code>MangoCrudServiceImpl&lt;Mapper, Entity&gt;</code>，优先复用 <code>createByCommand</code>、<code>updateByCommand</code>、<code>deleteById</code>、<code>detailById</code>、<code>pageByQuery</code>。</li><li>Controller：优先继承 <code>BaseCrudController</code> 或显式调用真实 Service；不得返回假数据。</li><li>前端 API：必须调用真实后端 CRUD 路径，页面必须能完成新增、分页查询、详情或等价真实功能验证。</li></ul><p>模板或 CLI 改动必须用生成后的企业业务项目做真实验证，至少覆盖数据库 migration、后端启动、创建记录、分页回显、详情查询和前端页面调用。</p><h2 id="_0-2-数据库命名规则" tabindex="-1">0.2 数据库命名规则 <a class="header-anchor" href="#_0-2-数据库命名规则" aria-label="Permalink to &quot;0.2 数据库命名规则&quot;">​</a></h2><ul><li>Mango 主库默认使用 <code>mango</code>。</li><li>Mango 模块独立数据库统一使用 <code>mango_{module}</code>。</li><li><code>{module}</code> 默认取 <code>module-path</code>；没有 <code>module-path</code> 时取 <code>module-name</code> 去掉开头的 <code>mango-</code>，并将 <code>-</code> 转为 <code>_</code>。</li><li>示例：<code>mango-job</code> / <code>job</code> 对应 <code>mango_job</code>，<code>mango-system</code> / <code>system</code> 对应 <code>mango_system</code>。</li><li>第三方组件内部库如果归属某个 Mango 模块托管，默认共置到该模块库；如果独立部署，也必须在设计中写清所有权、migration 归属、账号权限和备份边界。</li><li>禁止新增 <code>job</code>、<code>system</code>、<code>file</code> 这类无 <code>mango_</code> 前缀的模块物理数据库名。</li><li>本地临时验证库和 worktree 库可以使用 <code>mango_dev_*</code>，但不得作为模块部署配置样例。</li></ul><h2 id="_0-3-租户自动隔离规则" tabindex="-1">0.3 租户自动隔离规则 <a class="header-anchor" href="#_0-3-租户自动隔离规则" aria-label="Permalink to &quot;0.3 租户自动隔离规则&quot;">​</a></h2><ul><li>继承 <code>TenantEntity</code> 或包含 <code>tenant_id</code> 的普通租户表默认纳入 MyBatis-Plus <code>TenantLineInnerInterceptor</code>。</li><li>普通 CRUD、BaseMapper、Wrapper、分页查询和自定义 Mapper/XML SQL 默认依赖租户插件自动追加 <code>tenant_id</code> 过滤。</li><li>业务代码禁止在普通租户表查询中重复手写 <code>.eq(Entity::getTenantId, currentTenantId)</code> 或等价 SQL 条件；确需跨租户、租户初始化或授权校验时必须显式建模并写明场景。</li><li>插入普通租户实体禁止手工 <code>setTenantId</code>；由 <code>PersistenceAuditMetaObjectHandler</code> 根据 <code>MangoContextHolder</code> / <code>PersistenceContext</code> 自动填充。</li><li>业务 VO 可以返回 <code>tenantId</code> 用于审计、诊断或跨租户管理页面展示，但不得把客户端传入的 <code>tenantId</code> 当作普通 CRUD 隔离条件。</li><li><code>mango.persistence.mybatis-plus.tenant.excluded-tables</code> 只配置全局元数据表、无租户字段表、跨租户授权关系表、迁移历史表和基础设施内部表；新增例外表必须说明所有权、访问权限和测试口径。</li><li>当前默认例外表包括 Flyway/Liquibase 历史表、KV 基础设施表、租户/字典/区域/平台配置表、授权资源/菜单/应用元数据表、前端运行时元数据表、身份用户和租户成员关系表。</li><li><code>mango.persistence.schema-validation.excluded-tables</code> 只用于结构校验例外，不等同于租户过滤例外；两份配置不得混用语义。</li><li>任务、异步、开放接口、远程 Worker、跨租户授权、租户初始化和平台运营场景必须在进入 Mapper 前显式建立租户上下文；缺少上下文时不得依赖默认平台租户静默执行。</li><li>非 Web 任务如果配置 <code>mango.persistence.mybatis-plus.tenant.default-tenant-id</code>，只能用于明确单租户任务或本地验证，不得作为多租户业务链路的隐式兜底。</li><li>自定义 Mapper SQL、XML SQL、<code>Db</code>/<code>DbHelper</code>/<code>DbUtil</code> 等绕开实体服务的访问必须有集成测试证明租户插件生效；插件无法覆盖的 SQL 必须显式标注例外并补权限/租户断言。</li></ul><h2 id="_1-事务规则" tabindex="-1">1. 事务规则 <a class="header-anchor" href="#_1-事务规则" aria-label="Permalink to &quot;1. 事务规则&quot;">​</a></h2><ul><li>写操作必须放在明确事务边界内。</li><li>读操作默认不开事务，确有需要再加。</li><li>同一业务动作只定义一个主事务边界。</li><li>不在内部私有调用上重复定义事务。</li></ul><h2 id="_2-模式切换" tabindex="-1">2. 模式切换 <a class="header-anchor" href="#_2-模式切换" aria-label="Permalink to &quot;2. 模式切换&quot;">​</a></h2><ul><li>单体或聚合部署使用本地事务。</li><li>微服务部署按项目基线使用分布式事务。</li><li>事务模式通过配置切换，不靠业务代码分叉。</li></ul><h2 id="_3-数据访问规则" tabindex="-1">3. 数据访问规则 <a class="header-anchor" href="#_3-数据访问规则" aria-label="Permalink to &quot;3. 数据访问规则&quot;">​</a></h2><ul><li>持久化层只做数据访问。</li><li>业务判断放业务层。</li><li>跨域数据不通过跨表 join 解决。</li><li>Mapper 入参不得使用 API 协议模型，包括 <code>Command</code>、<code>Query</code>、<code>VO</code> 和 Controller 请求对象。</li><li>Service 调 Mapper 前必须完成协议模型到持久化模型的转换。</li></ul><h2 id="_4-设计要求" tabindex="-1">4. 设计要求 <a class="header-anchor" href="#_4-设计要求" aria-label="Permalink to &quot;4. 设计要求&quot;">​</a></h2><ul><li>事务范围尽量小。</li><li>长事务必须拆分。</li><li>有副作用的外部调用要考虑幂等和补偿。</li></ul><h2 id="_5-禁止事项" tabindex="-1">5. 禁止事项 <a class="header-anchor" href="#_5-禁止事项" aria-label="Permalink to &quot;5. 禁止事项&quot;">​</a></h2><ul><li>在事务里做无关长耗时操作</li><li>把事务注解贴满所有方法</li><li>用数据库实现跨模块业务耦合</li><li>业务代码直接使用 JDBC 或 <code>JdbcTemplate</code></li><li>Mapper 方法使用注解 SQL</li></ul>',21)])])}const h=o(c,[["render",i]]);export{p as __pageData,h as default};
